<template>
	<view class="page">
		<view class="subscribe">
			<view class="item">
				<view class="label">
					订单状态通知
				</view>
				<u-switch v-model="list.order_notice_status" active-color="#f3d89c" @change="change"></u-switch>
			</view>
			<view class="item">
				<view class="label">
					分销佣金通知
				</view>
				<u-switch v-model="list.commission_status" active-color="#f3d89c" @change="change"></u-switch>
			</view>
			<view class="item">
				<view class="label">
					用户提现通知
				</view>
				<u-switch v-model="list.withdraw_notice_status" active-color="#f3d89c" @change="change"></u-switch>
			</view>
			<view class="item">
				<view class="label">
					收藏商品调价通知
				</view>
				<u-switch v-model="list.change_price_status" active-color="#f3d89c" @change="change"></u-switch>
			</view>
			<view class="item">
				<view class="label">
					订单售后通知
				</view>
				<u-switch v-model="list.complaint_notice_status" active-color="#f3d89c" @change="change"></u-switch>
			</view>

			<view class="item">
				<view class="label">
					新增下级通知
				</view>
				<u-switch v-model="list.add_team_status" active-color="#f3d89c" @change="change"></u-switch>
			</view>
			<!-- <view class="item">
				<view class="label">
					余额不足通知
				</view>
				<u-switch v-model="list.yuemoney_status" active-color="#f3d89c" @change="save"></u-switch>
			</view> -->

		</view>

		<view class="mark" v-if="show">

			<view class="modal">
				<u-icon class="close-icon" name="close" @click="show=false,list.yuemoney_status=false"
					:custom-style="{}"></u-icon>
				<view class="title">
					余额不足通知
				</view>
				<view class="form-item">
					<view class="label">
						余额设置{{' '}}
						<text class="require">*</text>
					</view>
					<view class="item-value">
						<input type="text" v-model="list.yuemoney" placeholder-style="color:#d8dbe3;" class="input"
							placeholder="请输入余额不足通知的阈值">
					</view>
				</view>

				<view class="tips">
					温馨提示：当余额不足时会进行提醒！
				</view>
				<view class="submit-btn" @click="saveyuemoney">
					确定
				</view>
			</view>
		</view>
	</view>


</template>

<script>
	export default {

		data() {
			return {
				list: {

					order_notice_status: false, //订单状态通知开关
					commission_status: false, //分销佣金通知
					withdraw_notice_status: false, //用户提现通知
					change_price_status: false, //商品调价通知
					complaint_notice_status: false, //订单售后通知
					add_team_status: false, //新增下级通知
					yuemoney_status: false, //余额不足通知
					yuemoney: '', //余额通知金额
					is_bind:1,
					url:'',
				},
				show: false
			}
		},
		onLoad() {
			this.loadData();
		},
		methods: {
			change(status) {
				let params = {};
				for (let key in this.list) {
					params[key] = (this.list[key] ? 1 : 0);
				}

				this.$u.api.setNoticeSetting(params)
					.then(res => {
						this.show = false
						this.$util.msg('修改成功');
					}).catch(res => {
						this.loadData()
					})
			
			},
			loadData() {
				this.$u.api.getNoticeSetting({})
					.then(res => {

						this.list = res
						
						if(!this.list.is_bind && this.list.url){
							uni.previewImage({
								current: 0, // 当前显示图片的索引值
								urls: [this.list.url], // 需要预览的图片列表，photoList要求必须是数组
							
							})
						}
					}).catch(res => {})
			},
			//设置余额提醒
			save(status) {


				if (status) {
					this.list.yuemoney_status = false
					this.show = true

				} else {
					this.change(status)
				}
			},
			saveyuemoney(){
				if(this.list.yuemoney == ''){
					this.$util.msg('请输入余额阈值')
					return;
				}
				this.list.yuemoney_status = true
				this.change(true)
				
				
				
			}
		}
	}
</script>

<style lang="scss" scoped scoped>
	page {
		background-color: #f5f7fa;
	}

	.page {
		width: 100%;
		overflow: hidden;
		height: 100%;
		display: flex;
		align-items: center;
		justify-content: flex-start;
		flex-direction: column;
		padding-top: 20rpx;
	}

	.subscribe {
		width: 714rpx;
		background: #FFFFFF;
		border-radius: 16rpx;
		margin: 0 auto;
		display: flex;
		align-items: center;
		justify-content: flex-start;
		flex-direction: column;
	}

	.subscribe .item {
		width: 644rpx;
		height: 120rpx;
		display: flex;
		align-items: center;
		justify-content: space-between;
	}

	.subscribe .item .label {
		font-size: 30rpx;
		font-family: PingFangSC-Medium, PingFang SC;
		font-weight: 500;
		color: #1e2331;
	}

	.mark {
		position: fixed;
		top: 0%;
		left: 0%;
		background: rgba(32, 37, 51, .2);
		height: 100%;
		width: 100%;
		display: flex;
		align-items: center;
		justify-content: center;
		z-index: 999;
	}

	.mark .modal {
		width: 686rpx;
		height: 516rpx;
		background: #FFFFFF;
		border-radius: 16rpx;
		position: relative;
	}

	.mark .modal .close-icon {
		position: absolute;
		font-size: 30rpx;
		color: #c5c9d2;
		top: 20rpx;
		right: 20rpx;
	}

	.mark .modal .title {
		font-size: 30rpx;
		font-family: PingFangSC-Medium, PingFang SC;
		font-weight: 500;
		color: #1e2331;
		display: flex;
		align-items: center;
		justify-content: center;
		margin-top: 40rpx;
	}

	.mark .modal .form-item {
		width: 100%;
		padding: 0 24rpx;
		margin-top: 52rpx;
		display: flex;
		align-items: center;
		flex-direction: column;
		gap: 24rpx;

	}

	.mark .modal .form-item .label {
		width: 100%;
		color: #1e2331;
		font-weight: 400;
		font-size: 28rpx;
		text-align: left;
	}

	.mark .modal .form-item .label .require {
		color: #e62936;
	}

	.mark .modal .form-item .item-value {
		width: 100%;
		background: #F1F3F7;
		border-radius: 10rpx;
		display: flex;
		align-items: center;
		justify-content: flex-start;
	}

	.mark .modal .form-item  .item-value .input {
		width: 638rpx;
		height: 80rpx;
		border-radius: 10rpx;
		border: 2rpx solid #C7CAD3;
		background-color: #fff;
		padding: 0 26rpx;
	}

	.mark .modal .tips {
		margin-top: 18rpx;
		font-size: 22rpx;
		font-family: PingFangSC-Regular, PingFang SC;
		font-weight: 400;
		color: #ff5f4d;
		width: 100%;
		text-align: center;
	}

	.mark .modal .submit-btn {
		width: 420rpx;
		height: 84rpx;
		// background: linear-gradient(90deg, #FE8A55 0%, #FF5F4D 100%);
		background: #0e0d0d;
		
		border-radius: 42rpx;
		margin: 0 auto;
		margin-top: 72rpx;
		display: flex;
		align-items: center;
		justify-content: center;
		font-size: 28rpx;
		font-family: PingFangSC-Regular, PingFang SC;
		font-weight: 400;
		color: #fff;
	}
</style>
